const e="https://openkotor.com/schemas/binary-format.schema.json",t="BWM",s=`BWM (Binary Walkmesh) is the walkmesh format used by KotOR I & II for area pathfinding and collision. The same binary layout is used for area walkmeshes (often as .wok or .bwm), placeable walkmeshes (.pwk), and door walkmeshes (.dwk)—only the file extension and usage differ.

Layout: a 136-byte header with file type (4 chars), version (4 chars), walkmesh type (u32), 48 bytes reserved, then a position (3× float) and pairs of counts and offsets for vertices, faces, walk types, normals, face plane coefficients, AABB tree nodes, walkable-faces adjacency matrix, edges, and perimeters. All multi-byte values are little-endian. Sections start at the offsets given in the header; use the counts to know how many records to read.

Parsing: Read the header. Vertices at offsetToVertices: verticesCount × 12 bytes (3× float each). Faces at offsetToFaces: facesCount × 12 bytes (3× int32 vertex indices). Walk types at offsetToWalkTypes: facesCount × 4 bytes (int32 surface/walk type per face). Normals at offsetToNormalizedInvertedNormals: facesCount × 12 bytes (3× float per face). Face plane coefficients at offsetToFacePlanesCoefficien: facesCount × 4 bytes (float). AABB nodes at offsetToAABBs: aabbCount × 44 bytes (min/max box, face index, and tree links). Adjacency at offsetToWalkableFacesEdgesAdjacencyMatrix: walkableFacesEdgesAdjacencyMatrixCount × 12 bytes (3× int32 per walkable face; -1 = non-walkable edge). Edges at offsetToEdges: edgesCount × 8 bytes (index int32, transition int32). Perimeters at offsetToPerimeters: perimetersCount × 4 bytes (int32 cumulative edge count per perimeter; perimeter i uses edges from (prev cumulative) to (this cumulative) - 1 in the edge block).

Writing: Lay out data blocks in the order above (typically vertices immediately after the header), compute each section's offset, then write the header with all counts and offsets. AABB nodes store 6 floats (min/max bounds) then 5 int32s (face index, reserved, splitting plane axis, left and right child offsets). Adjacency encodes each adjacent face edge as faceIndex×3 + edgeIndexOnThatFace, or -1 for non-walkable. Perimeter table holds cumulative edge counts so the edge block is ordered by perimeter.`,i="little",n="Header",o={Header:{kind:"struct",description:"Fixed 136-byte header. fileType and version are 4-byte strings. walkMeshType (u32) controls collision. position is mesh origin (Vector3f). Remaining fields are (count, offset) pairs for each data section; all offsets are file-relative. Layout: 0–3 fileType, 4–7 version, 8–11 walkMeshType, 12–59 reserved, 60–71 position, 72–75 verticesCount, 76–79 offsetToVertices, 80–83 facesCount, 84–87 offsetToFaces, 88–91 offsetToWalkTypes, 92–95 offsetToNormalizedInvertedNormals, 96–99 offsetToFacePlanesCoefficien, 100–103 aabbCount, 104–107 offsetToAABBs, 108–111 unknownEntry, 112–115 walkableFacesEdgesAdjacencyMatrixCount, 116–119 offsetToWalkableFacesEdgesAdjacencyMatrix, 120–123 edgesCount, 124–127 offsetToEdges, 128–131 perimetersCount, 132–135 offsetToPerimeters.",fields:[{name:"File Type",type:{kind:"string",length:4},description:"File type magic. Offset 0, 4 bytes."},{name:"Version",type:{kind:"string",length:4},description:"Format version. Offset 4, 4 bytes."},{name:"Walk Mesh Type",type:"u32",description:"0 = NONE, 1 = AABB. Offset 8, 4 bytes."},{name:"Reserved",type:{kind:"bytes",length:48},description:"Reserved; keep zero. Offset 12, 48 bytes."},{name:"Position",type:"Vector3f",description:"Mesh origin. Offset 60, 12 bytes."},{name:"Vertices Count",type:"u32",description:"Number of vertices. Offset 72, 4 bytes."},{name:"Offset To Vertices",type:"u32",description:"File offset of vertex array. Offset 76, 4 bytes."},{name:"Faces Count",type:"u32",description:"Number of faces. Offset 80, 4 bytes."},{name:"Offset To Faces",type:"u32",description:"File offset of face array. Offset 84, 4 bytes."},{name:"Offset To Walk Types",type:"u32",description:"File offset of walk types array. Offset 88, 4 bytes."},{name:"Offset To Normalized Inverted Normals",type:"u32",description:"File offset of face normals array. Offset 92, 4 bytes."},{name:"Offset To Face Planes Coefficien",type:"u32",description:"File offset of face plane coefficients. Offset 96, 4 bytes."},{name:"AABB Count",type:"u32",description:"Number of AABB nodes. Offset 100, 4 bytes."},{name:"Offset To AABBs",type:"u32",description:"File offset of AABB array. Offset 104, 4 bytes."},{name:"Unknown Entry",type:"u32",description:"Unknown; often 0. Offset 108, 4 bytes."},{name:"Walkable Faces Edges Adjacency Matrix Count",type:"u32",description:"Number of adjacency rows. Offset 112, 4 bytes."},{name:"Offset To Walkable Faces Edges Adjacency Matrix",type:"u32",description:"File offset of adjacency matrix. Offset 116, 4 bytes."},{name:"Edges Count",type:"u32",description:"Total edge records. Offset 120, 4 bytes."},{name:"Offset To Edges",type:"u32",description:"File offset of edge array. Offset 124, 4 bytes."},{name:"Perimeters Count",type:"u32",description:"Number of perimeters. Offset 128, 4 bytes."},{name:"Offset To Perimeters",type:"u32",description:"File offset of perimeter table. Offset 132, 4 bytes."}]},Vector3f:{kind:"struct",description:"Three floats (x, y, z). Total size: 12 bytes. Layout: offset 0–3 x, 4–7 y, 8–11 z. Used in header for position.",fields:[{name:"Position X",type:"f32",description:"X component. Offset 0, 4 bytes."},{name:"Position Y",type:"f32",description:"Y component. Offset 4, 4 bytes."},{name:"Position Z",type:"f32",description:"Z component. Offset 8, 4 bytes."}]},Vertex:{kind:"struct",description:"One vertex position. Total size: 12 bytes (3× f32). Layout: offset 0–3 x, 4–7 y, 8–11 z. Array length = verticesCount.",fields:[{name:"Position X",type:"f32",description:"X coordinate. Offset 0, 4 bytes."},{name:"Position Y",type:"f32",description:"Y coordinate. Offset 4, 4 bytes."},{name:"Position Z",type:"f32",description:"Z coordinate. Offset 8, 4 bytes."}]},Face:{kind:"struct",description:"One triangular face: three vertex indices as int32. Total size: 12 bytes. Layout: offset 0–3 first vertex, 4–7 second vertex, 8–11 third vertex. Winding order matters for normals.",fields:[{name:"First Vertex Index",type:"s32",description:"Vertex index for first corner. Offset 0, 4 bytes."},{name:"Second Vertex Index",type:"s32",description:"Vertex index for second corner. Offset 4, 4 bytes."},{name:"Third Vertex Index",type:"s32",description:"Vertex index for third corner. Offset 8, 4 bytes."}]},FaceWalkType:{kind:"struct",description:"Surface/walk type for a single face. Total size: 4 bytes. One record per face; array length = facesCount. Indexed by face index; used for pathfinding and material type.",fields:[{name:"Walk Type Index",type:"s32",description:"Walk/surface type ID for this face. Offset 0, 4 bytes. References surface properties (e.g. walkable, water)."}]},FaceNormal:{kind:"struct",description:"Normalized, inverted face normal for one face. Total size: 12 bytes (3× f32). One record per face; array length = facesCount. Stored normalized; sign is inverted from geometric normal.",fields:[{name:"Normal X",type:"f32",description:"X component of face normal. Offset 0, 4 bytes."},{name:"Normal Y",type:"f32",description:"Y component of face normal. Offset 4, 4 bytes."},{name:"Normal Z",type:"f32",description:"Z component of face normal. Offset 8, 4 bytes."}]},FacePlaneCoeff:{kind:"struct",description:"Plane equation coefficient for one face (e.g. d in ax+by+cz+d=0, with normal from FaceNormal). Total size: 4 bytes. One record per face; array length = facesCount.",fields:[{name:"Plane Coefficient",type:"f32",description:"Plane coefficient. Offset 0, 4 bytes. Used with face normal for point-in-plane tests."}]},AABBNode:{kind:"struct",description:"One AABB tree node. Total size: 44 bytes. Layout: 6× f32 (min/max bounds), then 5× s32 (face index, reserved, splitting plane, left and right child offsets). Child offsets are byte offsets from the start of the AABB block (offsetToAABBs), or -1 for no child. Array length = aabbCount.",fields:[{name:"Bounds Minimum X",type:"f32",description:"AABB minimum X. Offset 0, 4 bytes."},{name:"Bounds Minimum Y",type:"f32",description:"AABB minimum Y. Offset 4, 4 bytes."},{name:"Bounds Minimum Z",type:"f32",description:"AABB minimum Z. Offset 8, 4 bytes."},{name:"Bounds Maximum X",type:"f32",description:"AABB maximum X. Offset 12, 4 bytes."},{name:"Bounds Maximum Y",type:"f32",description:"AABB maximum Y. Offset 16, 4 bytes."},{name:"Bounds Maximum Z",type:"f32",description:"AABB maximum Z. Offset 20, 4 bytes."},{name:"Face Index",type:"s32",description:"Face index for leaf node, or -1 for internal node. Offset 24, 4 bytes."},{name:"Reserved Or Unknown",type:"s32",description:"Reserved or unknown; often 4 in existing files. Offset 28, 4 bytes."},{name:"Splitting Plane Axis Index",type:"s32",description:"Axis index used to split this node. Offset 32, 4 bytes."},{name:"Left Child Node Offset",type:"s32",description:"Byte offset from start of AABB block to left child node, or -1. Offset 36, 4 bytes."},{name:"Right Child Node Offset",type:"s32",description:"Byte offset from start of AABB block to right child node, or -1. Offset 40, 4 bytes."}]},AdjacencyEntry:{kind:"struct",description:"One row of the walkable-faces adjacency matrix: three int32s, one per edge (side) of the walkable face. Total size: 12 bytes. Value ≥ 0: adjacent face edge index = value; face index = value÷3, edge on that face = value mod 3. -1: that edge is non-walkable. Array length = walkableFacesEdgesAdjacencyMatrixCount.",fields:[{name:"Adjacent Face Edge Index For Side 0",type:"s32",description:"Adjacent face edge index for triangle side 0, or -1 if non-walkable. Offset 0, 4 bytes."},{name:"Adjacent Face Edge Index For Side 1",type:"s32",description:"Adjacent face edge index for triangle side 1, or -1 if non-walkable. Offset 4, 4 bytes."},{name:"Adjacent Face Edge Index For Side 2",type:"s32",description:"Adjacent face edge index for triangle side 2, or -1 if non-walkable. Offset 8, 4 bytes."}]},Edge:{kind:"struct",description:"One edge record in the edge list. Total size: 8 bytes. Array length = edgesCount; stored in perimeter order (all edges of perimeter 0, then perimeter 1, etc.). The edge index typically encodes face×3 + edge.",fields:[{name:"Edge Index",type:"s32",description:"Edge index (e.g. faceIndex×3 + edgeIndexOnFace). Offset 0, 4 bytes."},{name:"Transition Destination ID",type:"s32",description:"Transition ID (e.g. door or trigger reference). Offset 4, 4 bytes."}]},PerimeterEntry:{kind:"struct",description:"One entry in the perimeter table: cumulative edge count. Total size: 4 bytes. Array length = perimetersCount. Entry i gives the exclusive end offset into the edge block for perimeter i; start is entry i-1 (or 0). So perimeter i uses edges from index (i==0 ? 0 : perimeter[i-1]) to perimeter[i]-1.",fields:[{name:"Cumulative Edge Count",type:"s32",description:"Cumulative number of edges through this perimeter. Offset 0, 4 bytes. Interpret as exclusive end index into the edge block for this perimeter."}]}},a={headerSize:136,vertexSize:12,faceSize:12,walkTypeSize:4,normalSize:12,facePlaneCoeffSize:4,aabbNodeSize:44,adjacencyEntrySize:12,edgeSize:8,perimeterEntrySize:4,WalkMeshType:{NONE:0,AABB:1}},r=[{name:"header",typeRef:"Header",offset:0,size:136,description:"Fixed 136-byte header. Contains file type, version, walkmesh type, position, and (count, offset) pairs for every data section. All section offsets are from the start of the file."},{name:"vertices",typeRef:"Vertex",offset:"Offset To Vertices",size:"Vertices Count * 12",description:"Vertex array. Section size = verticesCount × 12 bytes. Contiguous array of Vertex (3× f32); index i is vertex i."},{name:"faces",typeRef:"Face",offset:"Offset To Faces",size:"Faces Count * 12",description:"Face index array. Section size = facesCount × 12 bytes. Contiguous array of Face (3× s32 vertex indices); index i is face i."},{name:"walkTypes",typeRef:"FaceWalkType",offset:"Offset To Walk Types",size:"Faces Count * 4",description:"Walk/surface type per face. Section size = facesCount × 4 bytes. One FaceWalkType (s32) per face; index i corresponds to face i."},{name:"normals",typeRef:"FaceNormal",offset:"Offset To Normalized Inverted Normals",size:"Faces Count * 12",description:"Face normals (normalized, inverted). Section size = facesCount × 12 bytes. One FaceNormal (3× f32) per face; index i corresponds to face i."},{name:"facePlaneCoefficients",typeRef:"FacePlaneCoeff",offset:"Offset To Face Planes Coefficien",size:"Faces Count * 4",description:"Face plane coefficient per face. Section size = facesCount × 4 bytes. One FacePlaneCoeff (f32) per face; used with FaceNormal for plane tests."},{name:"aabbNodes",typeRef:"AABBNode",offset:"Offset To AABBs",size:"AABB Count * 44",description:"AABB tree. Section size = aabbCount × 44 bytes. Contiguous array of AABBNode. Child offsets in each node are relative to the start of this section (offsetToAABBs)."},{name:"walkableFacesAdjacency",typeRef:"AdjacencyEntry",offset:"Offset To Walkable Faces Edges Adjacency Matrix",size:"Walkable Faces Edges Adjacency Matrix Count * 12",description:"Walkable-faces adjacency matrix. Section size = walkableFacesEdgesAdjacencyMatrixCount × 12 bytes. One AdjacencyEntry (3× s32) per walkable face; row i corresponds to walkable face i."},{name:"edges",typeRef:"Edge",offset:"Offset To Edges",size:"Edges Count * 8",description:"Edge list. Section size = edgesCount × 8 bytes. Contiguous array of Edge (index s32, transition s32). Stored in perimeter order: edges for perimeter 0, then perimeter 1, etc. Perimeter bounds given by perimeters section."},{name:"perimeters",typeRef:"PerimeterEntry",offset:"Offset To Perimeters",size:"Perimeters Count * 4",description:"Perimeter table: cumulative edge counts. Section size = perimetersCount × 4 bytes. One PerimeterEntry (s32) per perimeter. Perimeter i uses edges in the edge block from index (i==0 ? 0 : perimeter[i-1]) to perimeter[i]-1."}],f={$schema:e,name:t,description:s,endianness:i,root:n,types:o,constants:a,sections:r};export{e as $schema,a as constants,f as default,s as description,i as endianness,t as name,n as root,r as sections,o as types};
